    b"{% endfor %}\x0a        {% endif %}\x0a\x0a        Session memories:\x0a        {% for memor"
    b"y in session_memories %}\x0a        - {{ memory.title }}\x0a          Tags: {{ memory."
    b"tags }}\x0a          created_at: {{ memory.created_at }}\x0a          updated_at: {{ m"
    b"emory.updated_at }}\x0a          read_at: {{ memory.read_at }}\x0a          {{ memory."
    b"description }}\x0a        {% endfor %}\x0a\x0a        User preferences:\x0a        {% for pr"
